/**
 * ContentLabPage — A/B test plan management for content experiments.
 *
 * Features:
 * - A/B test plan list as a table
 * - Columns: test group, direction, content, budget, status
 * - Scale-up rules / stop rules display
 * - Create new test plan button
 */
import React, { useMemo, useState } from 'react';
import {
  Box,
  Typography,
  Card,
  CardContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Chip,
  Button,
  Alert,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Stack,
  CircularProgress,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import ScienceIcon from '@mui/icons-material/Science';
import { useBrandStore } from '@/shared/stores/brandStore';
import { db } from '@/shared/db/db';
import { useLiveQuery } from 'dexie-react-hooks';
import type { StrategyCard } from '@/shared/types/strategy';

interface TestPlan {
  id: string;
  group: string;
  direction: string;
  content: string;
  budget: string;
  status: 'planning' | 'running' | 'completed' | 'stopped';
  scaleUpRule: string;
  stopRule: string;
  kpi: string;
  createdAt: string;
}

const ContentLabPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);

  const strategyCards = useLiveQuery(
    () =>
      currentBrandId
        ? db.strategyCards.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as StrategyCard[]),
    [currentBrandId],
  );

  const [dialogOpen, setDialogOpen] = useState(false);
  const [newPlan, setNewPlan] = useState({
    group: 'A',
    direction: '',
    content: '',
    budget: '',
    scaleUpRule: 'CTR > 3% 且互动率 > 5%',
    stopRule: 'CTR < 1% 或 CPA 超预算 50%',
    kpi: '',
  });

  // Derive test plans from strategy cards' abTestVariables
  const testPlans: TestPlan[] = useMemo(() => {
    if (!strategyCards) return [];
    const plans: TestPlan[] = [];
    strategyCards
      .filter((s) => s.reviewStatus === 'confirmed')
      .forEach((s) => {
        if (s.abTestVariables && s.abTestVariables.length > 0) {
          s.abTestVariables.forEach((v, vi) => {
            plans.push({
              id: `${s.id}-${vi}`,
              group: v.group,
              direction: v.direction,
              content: s.contentDirection?.substring(0, 80) ?? '',
              budget: s.budgetSuggestion ?? '未设置',
              status: s.status === 'active' ? 'running' : 'planning',
              scaleUpRule: 'CTR > 3% 且转化率提升',
              stopRule: 'CPM 超预算或 CTR < 1%',
              kpi: v.kpi,
              createdAt: new Date().toISOString().split('T')[0],
            });
          });
        }
      });
    return plans;
  }, [strategyCards]);

  const getStatusChip = (status: string) => {
    switch (status) {
      case 'planning':
        return { label: '规划中', color: 'default' as const };
      case 'running':
        return { label: '执行中', color: 'success' as const };
      case 'completed':
        return { label: '已完成', color: 'primary' as const };
      case 'stopped':
        return { label: '已停止', color: 'error' as const };
      default:
        return { label: status, color: 'default' as const };
    }
  };

  if (!currentBrandId) {
    return (
      <Box sx={{ p: 4, textAlign: 'center' }}>
        <Alert severity="info">请先在顶部选择一个品牌</Alert>
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3 }}>
      {/* Header */}
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 3 }}>
        <Box>
          <Typography variant="h5" fontWeight={700} gutterBottom>
            🧪 内容实验室
          </Typography>
          <Typography variant="body2" color="text.secondary">
            A/B 测试方案管理与执行追踪
          </Typography>
        </Box>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => setDialogOpen(true)}
        >
          新建测试
        </Button>
      </Box>

      {/* Rules Summary */}
      <Box sx={{ display: 'flex', gap: 2, mb: 3, flexDirection: { xs: 'column', md: 'row' } }}>
        <Card sx={{ flex: 1 }}>
          <CardContent>
            <Typography variant="subtitle2" fontWeight={600} gutterBottom color="success.main">
              📈 放大规则
            </Typography>
            <Typography variant="body2" color="text.secondary">
              CTR {'>'} 3% 且互动率 {'>'} 5%，连续 3 天达标后自动放大预算 50%
            </Typography>
          </CardContent>
        </Card>
        <Card sx={{ flex: 1 }}>
          <CardContent>
            <Typography variant="subtitle2" fontWeight={600} gutterBottom color="error.main">
              🛑 停止规则
            </Typography>
            <Typography variant="body2" color="text.secondary">
              CTR {'<'} 1% 或 CPA 超出预算 50% 或连续 2 天负反馈率 {'>'} 10%
            </Typography>
          </CardContent>
        </Card>
      </Box>

      {/* Test Plans Table */}
      {strategyCards === undefined ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
          <CircularProgress />
        </Box>
      ) : testPlans.length === 0 ? (
        <Card>
          <CardContent sx={{ textAlign: 'center', py: 6 }}>
            <ScienceIcon sx={{ fontSize: 48, color: 'text.disabled', mb: 1 }} />
            <Typography variant="h6" color="text.secondary" gutterBottom>
              暂无测试方案
            </Typography>
            <Typography variant="body2" color="text.disabled" sx={{ mb: 2 }}>
              确认策略卡后，A/B 测试变量将自动生成为测试方案
            </Typography>
            <Button variant="outlined" startIcon={<AddIcon />} onClick={() => setDialogOpen(true)}>
              手动创建测试方案
            </Button>
          </CardContent>
        </Card>
      ) : (
        <TableContainer component={Paper} variant="outlined">
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell sx={{ fontWeight: 600 }}>测试组</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>方向</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>内容</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>预算</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>KPI</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>状态</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {testPlans.map((plan) => {
                const statusInfo = getStatusChip(plan.status);
                return (
                  <TableRow key={plan.id} hover>
                    <TableCell>
                      <Chip
                        label={`${plan.group} 组`}
                        size="small"
                        color="primary"
                        variant="outlined"
                        sx={{ fontWeight: 600 }}
                      />
                    </TableCell>
                    <TableCell>{plan.direction}</TableCell>
                    <TableCell>
                      {plan.content.length > 60
                        ? plan.content.substring(0, 60) + '...'
                        : plan.content}
                    </TableCell>
                    <TableCell>{plan.budget}</TableCell>
                    <TableCell>
                      <Chip label={plan.kpi} size="small" variant="outlined" sx={{ fontSize: 11 }} />
                    </TableCell>
                    <TableCell>
                      <Chip
                        label={statusInfo.label}
                        size="small"
                        color={statusInfo.color}
                      />
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Rules table per test plan */}
      {testPlans.length > 0 && (
        <Card sx={{ mt: 3 }}>
          <CardContent>
            <Typography variant="subtitle1" fontWeight={600} gutterBottom>
              📋 测试规则明细
            </Typography>
            <TableContainer component={Paper} variant="outlined">
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell sx={{ fontWeight: 600 }}>测试组</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>放大规则</TableCell>
                    <TableCell sx={{ fontWeight: 600 }}>停止规则</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {testPlans.map((plan) => (
                    <TableRow key={`rules-${plan.id}`}>
                      <TableCell>
                        <Chip label={`${plan.group} 组`} size="small" color="primary" variant="outlined" />
                      </TableCell>
                      <TableCell>
                        <Typography variant="body2" color="success.main">
                          {plan.scaleUpRule}
                        </Typography>
                      </TableCell>
                      <TableCell>
                        <Typography variant="body2" color="error.main">
                          {plan.stopRule}
                        </Typography>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </CardContent>
        </Card>
      )}

      {/* Create Test Plan Dialog */}
      <Dialog open={dialogOpen} onClose={() => setDialogOpen(false)} maxWidth="sm" fullWidth>
        <DialogTitle>新建 A/B 测试方案</DialogTitle>
        <DialogContent>
          <Stack spacing={2} sx={{ mt: 1 }}>
            <FormControl fullWidth size="small">
              <InputLabel>测试组</InputLabel>
              <Select
                value={newPlan.group}
                label="测试组"
                onChange={(e) => setNewPlan({ ...newPlan, group: e.target.value })}
              >
                <MenuItem value="A">A 组</MenuItem>
                <MenuItem value="B">B 组</MenuItem>
                <MenuItem value="C">C 组</MenuItem>
              </Select>
            </FormControl>
            <TextField
              label="测试方向"
              size="small"
              fullWidth
              value={newPlan.direction}
              onChange={(e) => setNewPlan({ ...newPlan, direction: e.target.value })}
              placeholder="如：痛点切入 vs 场景共鸣"
            />
            <TextField
              label="内容描述"
              size="small"
              fullWidth
              multiline
              rows={2}
              value={newPlan.content}
              onChange={(e) => setNewPlan({ ...newPlan, content: e.target.value })}
            />
            <TextField
              label="预算"
              size="small"
              fullWidth
              value={newPlan.budget}
              onChange={(e) => setNewPlan({ ...newPlan, budget: e.target.value })}
              placeholder="如：500-1000元/组"
            />
            <TextField
              label="KPI"
              size="small"
              fullWidth
              value={newPlan.kpi}
              onChange={(e) => setNewPlan({ ...newPlan, kpi: e.target.value })}
              placeholder="如：CTR > 3%, CVR > 2%"
            />
            <TextField
              label="放大规则"
              size="small"
              fullWidth
              value={newPlan.scaleUpRule}
              onChange={(e) => setNewPlan({ ...newPlan, scaleUpRule: e.target.value })}
            />
            <TextField
              label="停止规则"
              size="small"
              fullWidth
              value={newPlan.stopRule}
              onChange={(e) => setNewPlan({ ...newPlan, stopRule: e.target.value })}
            />
          </Stack>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setDialogOpen(false)}>取消</Button>
          <Button
            variant="contained"
            onClick={() => {
              // In a real app, this would save to DB
              setDialogOpen(false);
            }}
            disabled={!newPlan.direction || !newPlan.content}
          >
            创建
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default ContentLabPage;
